('space', 'Weltraum', 'Space', '🚀', '#7C3AED'),
('soccer', 'Fußball', 'Soccer', '⚽', '#22C55E'),
('detective', 'Detektiv', 'Detective', '🔍', '#6B7280'),
('unicorn', 'Einhorn', 'Unicorn', '🦄', '#EC4899'),
('animals', 'Tiere', 'Animals', '🐾', '#A16207'),
('superhero', 'Superhelden', 'Superheroes', '🦸', '#DC2626'),
('circus', 'Zirkus', 'Circus', '🎪', '#F59E0B'),
('knight', 'Ritter', 'Knights', '⚔️', '#78716C'),
('mermaid', 'Meerjungfrau', 'Mermaid', '🧜‍♀️', '#06B6D4'),
('jungle', 'Dschungel', 'Jungle', '🌴', '#15803D'),
('no-theme', 'Ohne Motto', 'No Theme', '🎈', '#7C3AED');

-- ============================================================
-- GAMES (80+ Spiele)
-- ============================================================

-- === CLASSIC PARTY GAMES (all themes) ===
INSERT INTO public.games (name_de, name_en, description_de, description_en, instructions_de, instructions_en, min_age, max_age, location, activity, duration_minutes, min_players, materials_de, materials_en, theme_slugs) VALUES
('Reise nach Jerusalem', 'Musical Chairs', 'Ein Klassiker! Stühle im Kreis, Musik an, und wenn sie stoppt, muss jeder einen Platz finden.', 'A classic! Chairs in a circle, music plays, and when it stops everyone must find a seat.', '1. Stühle im Kreis aufstellen (ein Stuhl weniger als Kinder)\n2. Musik abspielen\n3. Kinder laufen um die Stühle\n4. Musik stoppen - jeder sucht einen Platz\n5. Wer keinen Platz findet, scheidet aus\n6. Einen Stuhl entfernen und wiederholen', '1. Place chairs in a circle (one fewer than children)\n2. Play music\n3. Children walk around chairs\n4. Stop the music - everyone finds a seat\n5. The one without a seat is out\n6. Remove one chair and repeat', 3, 12, 'indoor', 'active', 15, 4, ARRAY['Stühle', 'Musikbox'], ARRAY['Chairs', 'Speaker'], ARRAY['no-theme', 'princess', 'circus']),

('Stopptanz', 'Freeze Dance', 'Alle tanzen zur Musik. Wenn die Musik stoppt, muss jeder einfrieren!', 'Everyone dances to music. When the music stops, everyone must freeze!', '1. Musik abspielen\n2. Alle Kinder tanzen\n3. Musik stoppen\n4. Wer sich noch bewegt, scheidet aus\n5. Letzter Tänzer gewinnt', '1. Play music\n2. All children dance\n3. Stop the music\n4. Anyone still moving is out\n5. Last dancer wins', 3, 10, 'both', 'wild', 10, 3, ARRAY['Musikbox'], ARRAY['Speaker'], ARRAY['no-theme', 'unicorn', 'circus', 'superhero']),

('Sackhüpfen', 'Sack Race', 'Wer hüpft am Schnellsten im Sack ins Ziel?', 'Who can hop the fastest in a sack to the finish line?', '1. Start- und Ziellinie markieren\n2. Jedes Kind steigt in einen Sack\n3. Auf Kommando loshüpfen\n4. Wer zuerst im Ziel ist, gewinnt', '1. Mark start and finish lines\n2. Each child gets into a sack\n3. Hop on command\n4. First to finish wins', 4, 12, 'outdoor', 'wild', 15, 3, ARRAY['JuteSäcke', 'Kreide für Markierung'], ARRAY['Burlap sacks', 'Chalk for marking'], ARRAY['no-theme', 'animals', 'circus']),

('Eierlauf', 'Egg and Spoon Race', 'Balance ein Ei auf dem Löffel und renne ins Ziel!', 'Balance an egg on a spoon and race to the finish!', '1. Start- und Ziellinie markieren\n2. Jedem Kind einen Löffel und ein Ei geben\n3. Ei auf den Löffel legen\n4. Zum Ziel laufen ohne das Ei fallen zu lassen\n5. Fällt das Ei, zurück zum Start', '1. Mark start and finish lines\n2. Give each child a spoon and egg\n3. Place egg on spoon\n4. Walk to finish without dropping egg\n5. If egg falls, back to start', 4, 12, 'outdoor', 'active', 15, 3, ARRAY['Löffel', 'Eier (hart gekocht oder Plastik)'], ARRAY['Spoons', 'Eggs (hard-boiled or plastic)'], ARRAY['no-theme', 'circus']),

('Topfschlagen', 'Pot Banging', 'Mit verbundenen Augen den Topf finden und den Preis gewinnen!', 'Blindfolded, find the pot and win the prize!', '1. Einen umgedrehten Topf mit einem Preis darunter auf den Boden stellen\n2. Kind bekommt Augen verbunden und einen KochLöffel\n3. Auf allen Vieren den Topf suchen\n4. Andere Kinder rufen "warm" oder "kalt"\n5. Topf gefunden = Preis gewonnen!', '1. Place an upturned pot with a prize underneath on the floor\n2. Blindfold the child and give them a wooden spoon\n3. On hands and knees, search for the pot\n4. Other children call "warm" or "cold"\n5. Found the pot = win the prize!', 3, 8, 'indoor', 'calm', 20, 3, ARRAY['Topf', 'KochLöffel', 'Augenbinde', 'kleine Preise'], ARRAY['Pot', 'Wooden spoon', 'Blindfold', 'Small prizes'], ARRAY['no-theme', 'pirates', 'knight']),

('Schokoladen-Wettessen', 'Chocolate Race', 'Würfle eine 6, dann darfst du Schokolade essen - aber nur mit Messer und Gabel!', 'Roll a 6, then you can eat chocolate - but only with knife and fork!', '1. Schokolade auf Teller in die Mitte\n2. Mütze, Schal, Handschuhe bereitlegen\n3. Reihum Würfeln\n4. Bei einer 6: Mütze, Schal, Handschuhe anziehen\n5. Mit Messer und Gabel Schokolade essen\n6. Nächste 6 von anderem Kind = Wechsel', '1. Place chocolate on a plate in the center\n2. Prepare hat, scarf, gloves\n3. Take turns rolling dice\n4. On a 6: put on hat, scarf, gloves\n5. Eat chocolate with knife and fork\n6. Next 6 by another child = switch', 5, 12, 'indoor', 'active', 20, 4, ARRAY['Tafel Schokolade', 'Würfel', 'Mütze', 'Schal', 'Handschuhe', 'Messer', 'Gabel'], ARRAY['Chocolate bar', 'Dice', 'Hat', 'Scarf', 'Gloves', 'Knife', 'Fork'], ARRAY['no-theme']),

('Luftballon-Tanz', 'Balloon Dance', 'Tanzt zu zweit mit einem Luftballon zwischen euch - er darf nicht runterfallen!', 'Dance in pairs with a balloon between you - it must not fall!', '1. Paare bilden\n2. Luftballon zwischen die Körper klemmen\n3. Musik abspielen\n4. Tanzen ohne den Ballon zu verlieren\n5. Wer den Ballon fallen lässt, scheidet aus', '1. Form pairs\n2. Place balloon between bodies\n3. Play music\n4. Dance without losing the balloon\n5. If balloon falls, pair is out', 4, 10, 'indoor', 'active', 15, 4, ARRAY['Luftballons', 'Musikbox'], ARRAY['Balloons', 'Speaker'], ARRAY['no-theme', 'unicorn', 'princess', 'circus']),

('Mumienwickeln', 'Mummy Wrap', 'Wickelt euren Partner so schnell wie möglich in Toilettenpapier ein!', 'Wrap your partner in toilet paper as fast as possible!', '1. Teams zu zweit bilden\n2. Jedes Team bekommt eine Rolle Toilettenpapier\n3. Auf Kommando: Ein Kind wickelt das andere ein\n4. Wer zuerst komplett eingewickelt ist, gewinnt', '1. Form teams of two\n2. Each team gets a roll of toilet paper\n3. On command: one child wraps the other\n4. First team to finish wrapping wins', 5, 12, 'indoor', 'active', 10, 4, ARRAY['Toilettenpapier-Rollen'], ARRAY['Toilet paper rolls'], ARRAY['no-theme', 'superhero']),

('Blindes Zeichnen', 'Blind Drawing', 'Ein Kind beschreibt ein Bild, die anderen Müssen es blind zeichnen!', 'One child describes a picture, the others must draw it blindly!', '1. Ein Kind zieht eine Karte mit einem Bild\n2. Es beschreibt das Bild mit Worten\n3. Die anderen zeichnen nach Beschreibung\n4. Vergleichen und lachen!', '1. One child draws a card with a picture\n2. They describe the picture with words\n3. Others draw based on the description\n4. Compare and laugh!', 5, 12, 'indoor', 'calm', 15, 3, ARRAY['Papier', 'Stifte', 'Bildkarten'], ARRAY['Paper', 'Pens', 'Picture cards'], ARRAY['no-theme', 'detective']),

('Stille Post', 'Telephone Game', 'Ein Wort wird geflüstert - was kommt am Ende raus?', 'A word is whispered around - what comes out at the end?', '1. Kinder sitzen im Kreis\n2. Erstes Kind fluestert ein Wort dem Nachbarn ins Ohr\n3. Jeder fluestert weiter\n4. Letztes Kind sagt laut, was angekommen ist\n5. Vergleich mit dem Originalwort', '1. Children sit in a circle\n2. First child whispers a word to neighbor\n3. Each one whispers to the next\n4. Last child says out loud what they heard\n5. Compare with the original word', 4, 12, 'both', 'calm', 10, 5, ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY['no-theme', 'detective']),

-- === PIRATE THEME GAMES ===
('Schatzsuche', 'Treasure Hunt', 'Folgt der Schatzkarte und findet den verborgenen Schatz!', 'Follow the treasure map and find the hidden treasure!', '1. Schatzkarte vorbereiten mit Hinweisen\n2. Schatz verstecken (Süßigkeiten/kleine Spielzeuge)\n3. Kinder folgen den Hinweisen\n4. Gemeinsam den Schatz finden und teilen', '1. Prepare treasure map with clues\n2. Hide treasure (sweets/small toys)\n3. Children follow the clues\n4. Find and share the treasure together', 4, 12, 'both', 'active', 30, 3, ARRAY['Schatzkarte', 'Schatz (Süßigkeiten)', 'Hinweiszettel'], ARRAY['Treasure map', 'Treasure (sweets)', 'Clue cards'], ARRAY['pirates', 'detective', 'jungle']),

('Piratenschiff-Rennen', 'Pirate Ship Race', 'Baut ein Schiff aus Kartons und rudert zum Ziel!', 'Build a ship from cardboard boxes and row to the finish!', '1. Große Kartons als Schiffe vorbereiten\n2. Teams bilden\n3. Kinder steigen in die Kartons\n4. Zum Ziel "rudern"\n5. Schnellstes Schiff gewinnt', '1. Prepare large boxes as ships\n2. Form teams\n3. Children get into boxes\n4. "Row" to the finish\n5. Fastest ship wins', 4, 10, 'outdoor', 'wild', 20, 4, ARRAY['Große Kartons', 'Farbe zum Bemalen'], ARRAY['Large cardboard boxes', 'Paint for decorating'], ARRAY['pirates']),

('Schatz-Tauchen', 'Treasure Diving', 'Taucht in die Schatztruhe und findet mit verbundenen Augen Goldmünzen!', 'Dive into the treasure chest and find gold coins blindfolded!', '1. Große Schüssel mit Sand/Reis fuellen\n2. Goldmünzen (Schokolade) verstecken\n3. Augen verbinden\n4. In der Schüssel nach Münzen tasten\n5. Wer die Meisten findet, gewinnt', '1. Fill large bowl with sand/rice\n2. Hide gold coins (chocolate)\n3. Blindfold children\n4. Feel for coins in the bowl\n5. Most coins wins', 3, 8, 'indoor', 'calm', 15, 3, ARRAY['Große Schüssel', 'Sand oder Reis', 'Schoko-Goldmünzen', 'Augenbinde'], ARRAY['Large bowl', 'Sand or rice', 'Chocolate gold coins', 'Blindfold'], ARRAY['pirates', 'mermaid']),

('Kanonenkugel-Weitwurf', 'Cannonball Throw', 'Werft die Kanonenkugeln so weit wie möglich!', 'Throw the cannonballs as far as possible!', '1. Schwarze Bälle oder bemalte TennisBälle als Kanonenkugeln\n2. Wurflinie markieren\n3. Jedes Kind wirft dreimal\n4. Weitester Wurf gewinnt', '1. Black balls or painted tennis balls as cannonballs\n2. Mark throwing line\n3. Each child throws three times\n4. Furthest throw wins', 4, 12, 'outdoor', 'active', 15, 3, ARRAY['Bälle (schwarz)', 'Kreide', 'Maßband'], ARRAY['Balls (black)', 'Chalk', 'Tape measure'], ARRAY['pirates', 'knight', 'superhero']),

('Planke-Lauf', 'Walk the Plank', 'Balanciert über die Planke, ohne ins Wasser zu fallen!', 'Balance across the plank without falling into the water!', '1. Holzbrett oder Balken auf den Boden legen\n2. Blaue Tücher als "Wasser" drumherum\n3. Kinder balancieren über die Planke\n4. Wer runterFällt, ist "nass"', '1. Place wooden plank on the ground\n2. Blue cloths as "water" around it\n3. Children balance across the plank\n4. Whoever falls off is "wet"', 3, 10, 'both', 'active', 10, 3, ARRAY['Holzbrett/Balken', 'Blaue Tücher'], ARRAY['Wooden plank', 'Blue cloths'], ARRAY['pirates', 'mermaid']),

-- === PRINCESS / UNICORN THEME GAMES ===
('Krönungszeremonie', 'Coronation Ceremony', 'Bastelt eure eigenen Kronen und Kürt die Geburtstagsprinzessin!', 'Craft your own crowns and crown the birthday princess!', '1. Bastelstation mit Kronen-Vorlagen aufbauen\n2. Glitzer, Sticker, Edelsteine bereitlegen\n3. Jedes Kind bastelt seine Krone\n4. Feierliche Krönung des Geburtstagskindes', '1. Set up craft station with crown templates\n2. Provide glitter, stickers, gems\n3. Each child crafts their crown\n4. Ceremonial crowning of birthday child', 3, 8, 'indoor', 'calm', 25, 3, ARRAY['Kronen-Vorlagen', 'Glitzer', 'Sticker', 'Kleber', 'Edelsteine (Plastik)'], ARRAY['Crown templates', 'Glitter', 'Stickers', 'Glue', 'Gems (plastic)'], ARRAY['princess', 'knight']),

('Einhorn-Ringwerfen', 'Unicorn Ring Toss', 'Werft die Ringe über das Einhorn-Horn!', 'Toss the rings over the unicorn horn!', '1. Einhorn-Standfigur aufstellen (Pappe/Styropor)\n2. Bunte Ringe vorbereiten\n3. Jedes Kind wirft 3 Ringe\n4. Meiste Treffer gewinnt', '1. Set up unicorn figure (cardboard/styrofoam)\n2. Prepare colorful rings\n3. Each child throws 3 rings\n4. Most hits wins', 3, 8, 'both', 'active', 15, 3, ARRAY['Einhorn-Figur', 'Bunte Wurfringe'], ARRAY['Unicorn figure', 'Colorful throwing rings'], ARRAY['unicorn', 'princess']),

('Prinzessinnen-Tanz', 'Princess Dance', 'Tanzt wie Prinzessinnen zum Königlichen Ball!', 'Dance like princesses at the royal ball!', '1. Klassische Musik oder Disney-Songs spielen\n2. Kinder tanzen elegant\n3. Bei Musik-Stopp: einfrieren in einer Prinzessinnen-Pose\n4. schönste Pose gewinnt eine Runde', '1. Play classical music or Disney songs\n2. Children dance elegantly\n3. When music stops: freeze in a princess pose\n4. Best pose wins a round', 3, 8, 'indoor', 'active', 15, 3, ARRAY['Musikbox', 'TuellRöcke (optional)'], ARRAY['Speaker', 'Tulle skirts (optional)'], ARRAY['princess', 'unicorn']),

('Regenbogenlauf', 'Rainbow Run', 'Sammelt alle Regenbogenfarben ein und seid die Schnellsten!', 'Collect all rainbow colors and be the fastest!', '1. Farbige Karten im Garten/Raum verstecken\n2. Jedes Kind bekommt eine Farbenliste\n3. Alle Farben des Regenbogens finden\n4. Wer zuerst alle hat, gewinnt', '1. Hide colored cards in garden/room\n2. Each child gets a color list\n3. Find all rainbow colors\n4. First to find all wins', 4, 10, 'both', 'active', 20, 3, ARRAY['Farbige Karten (7 Farben)', 'Farbenlisten'], ARRAY['Colored cards (7 colors)', 'Color lists'], ARRAY['unicorn', 'no-theme']),

('Zauberstab-Basteln', 'Magic Wand Crafting', 'Bastelt euren eigenen magischen Zauberstab!', 'Craft your own magical wand!', '1. HolzStäbe oder Strohhalme als Basis\n2. Sternform aus Pappe ausschneiden\n3. Mit Glitzer und Bändern dekorieren\n4. Fertige ZauberStäbe bewundern', '1. Wooden sticks or straws as base\n2. Cut star shape from cardboard\n3. Decorate with glitter and ribbons\n4. Admire finished wands', 3, 8, 'indoor', 'calm', 20, 3, ARRAY['HolzStäbe', 'Pappe', 'Glitzer', 'Bänder', 'Kleber', 'Schere'], ARRAY['Wooden sticks', 'Cardboard', 'Glitter', 'Ribbons', 'Glue', 'Scissors'], ARRAY['unicorn', 'princess']),

-- === DINOSAUR THEME GAMES ===
('Dino-Eier-Ausgraben', 'Dino Egg Dig', 'Grabt die versteckten Dinosaurier-Eier aus!', 'Dig up the hidden dinosaur eggs!', '1. Kleine Spielzeug-Dinos in Gips-Eier eingiessen (vorher vorbereiten)\n2. Kinder bekommen kleine Hämmer/Meissel\n3. Eier vorsichtig aufklopfen\n4. Dino befreien und behalten', '1. Cast small toy dinos in plaster eggs (prepare beforehand)\n2. Children get small hammers/chisels\n3. Carefully crack open eggs\n4. Free the dino and keep it', 4, 10, 'both', 'calm', 20, 3, ARRAY['Gipseier mit Dino-Figuren', 'Kleine Hämmer', 'Zeitungspapier als Unterlage'], ARRAY['Plaster eggs with dino figures', 'Small hammers', 'Newspaper as base'], ARRAY['dinosaurs']),

('Dino-Fußabdrücke', 'Dino Footprints', 'Folgt den Dino-Spuren und findet das Dino-Nest!', 'Follow the dino tracks and find the dino nest!', '1. Dino-Fußabdrücke aus Pappe ausschneiden\n2. Spuren im Haus/Garten auslegen\n3. Kinder folgen den Spuren\n4. Am Ende: Dino-Nest mit überraschung', '1. Cut dino footprints from cardboard\n2. Lay tracks in house/garden\n3. Children follow the tracks\n4. At the end: dino nest with surprise', 3, 8, 'both', 'active', 20, 3, ARRAY['Pappe', 'Schere', 'Farbe', 'überraschung für das Nest'], ARRAY['Cardboard', 'Scissors', 'Paint', 'Surprise for the nest'], ARRAY['dinosaurs', 'jungle']),

('Lava-Lauf', 'Lava Run', 'Der Boden ist Lava! Springt von Insel zu Insel!', 'The floor is lava! Jump from island to island!', '1. Kissen, Teppichstücke oder Pappe als Inseln verteilen\n2. Kinder Müssen von Insel zu Insel springen\n3. Wer den Boden berührt, ist in der Lava\n4. Wer alle Inseln schafft, gewinnt', '1. Distribute pillows, carpet pieces or cardboard as islands\n2. Children must jump from island to island\n3. Touching the floor means falling in lava\n4. Completing all islands wins', 4, 10, 'indoor', 'wild', 15, 3, ARRAY['Kissen', 'Teppichstücke', 'Pappe'], ARRAY['Pillows', 'Carpet pieces', 'Cardboard'], ARRAY['dinosaurs', 'superhero']),

('Dino-Memory', 'Dino Memory', 'Findet die passenden Dino-Paare!', 'Find the matching dino pairs!', '1. Dino-Memory-Karten auslegen (verdeckt)\n2. Reihum je 2 Karten aufdecken\n3. Paar gefunden = behalten\n4. Meiste Paare gewinnt', '1. Lay out dino memory cards (face down)\n2. Take turns flipping 2 cards\n3. Found a pair = keep it\n4. Most pairs wins', 3, 8, 'indoor', 'calm', 15, 3, ARRAY['Dino-Memory-Karten'], ARRAY['Dino memory cards'], ARRAY['dinosaurs']),

('Vulkan-Experiment', 'Volcano Experiment', 'Baut einen Vulkan und lasst ihn ausbrechen!', 'Build a volcano and make it erupt!', '1. Vulkan aus Pappmache oder Sand formen\n2. Kleine Flasche in die Mitte\n3. Essig und Backpulver mischen\n4. Vulkan bricht aus!', '1. Form volcano from papier-mache or sand\n2. Small bottle in the center\n3. Mix vinegar and baking soda\n4. Volcano erupts!', 5, 12, 'outdoor', 'calm', 20, 3, ARRAY['Pappmache oder Sand', 'Kleine Flasche', 'Essig', 'Backpulver', 'Lebensmittelfarbe (rot)'], ARRAY['Papier-mache or sand', 'Small bottle', 'Vinegar', 'Baking soda', 'Food coloring (red)'], ARRAY['dinosaurs']),

-- === SPACE THEME GAMES ===
('Raketen-Start', 'Rocket Launch', 'Baut eure eigene Rakete und lasst sie fliegen!', 'Build your own rocket and launch it!', '1. Leere Plastikflaschen als RaketenKörper\n2. Pappe als Flügel ankleben\n3. Dekorieren\n4. Mit Wasser und Luft starten (Wasserrakete)', '1. Empty plastic bottles as rocket body\n2. Glue cardboard as wings\n3. Decorate\n4. Launch with water and air (water rocket)', 5, 12, 'outdoor', 'active', 25, 3, ARRAY['Plastikflaschen', 'Pappe', 'Kleber', 'Farbe', 'Wasserpumpe'], ARRAY['Plastic bottles', 'Cardboard', 'Glue', 'Paint', 'Water pump'], ARRAY['space']),

('Planeten-Lauf', 'Planet Run', 'Lauft von Planet zu Planet und sammelt Sterne!', 'Run from planet to planet and collect stars!', '1. Planeten-Stationen im Garten aufbauen\n2. An jeder Station eine Aufgabe lösen\n3. für jede gelöste Aufgabe einen Stern sammeln\n4. Meiste Sterne gewinnt', '1. Set up planet stations in the garden\n2. Solve a task at each station\n3. Collect a star for each solved task\n4. Most stars wins', 4, 10, 'outdoor', 'active', 25, 3, ARRAY['Planeten-Bilder', 'Stern-Aufkleber', 'Aufgabenkarten'], ARRAY['Planet pictures', 'Star stickers', 'Task cards'], ARRAY['space']),

('Alien-Jäger', 'Alien Hunter', 'Findet die versteckten Aliens bevor die Zeit abläuft!', 'Find the hidden aliens before time runs out!', '1. Kleine Alien-Figuren im Raum verstecken\n2. Kinder haben 5 Minuten Zeit\n3. Alle Aliens finden\n4. Wer die Meisten findet, gewinnt', '1. Hide small alien figures in the room\n2. Children have 5 minutes\n3. Find all aliens\n4. Most aliens found wins', 3, 8, 'indoor', 'active', 15, 3, ARRAY['Alien-Figuren (Plastik)', 'Timer'], ARRAY['Alien figures (plastic)', 'Timer'], ARRAY['space']),

('Sternbilder-Malen', 'Constellation Drawing', 'Verbindet die Sterne und malt eure eigenen Sternbilder!', 'Connect the stars and draw your own constellations!', '1. Schwarzes Papier und weiße Punkte (Sterne)\n2. Punkte mit weißem Stift verbinden\n3. Eigenes Sternbild erfinden\n4. Namen geben und vorstellen', '1. Black paper and white dots (stars)\n2. Connect dots with white pen\n3. Invent your own constellation\n4. Name it and present', 5, 12, 'indoor', 'calm', 20, 3, ARRAY['Schwarzes Papier', 'weiße Stifte', 'Glitzer-Aufkleber'], ARRAY['Black paper', 'White pens', 'Glitter stickers'], ARRAY['space']),

('Meteoriten-Abwehr', 'Meteorite Defense', 'Werft die Meteoriten-Bälle ab bevor sie einschlagen!', 'Throw the meteorite balls before they hit!', '1. Zielscheibe aufhaengen\n2. Bälle als Meteoriten\n3. Kinder werfen auf die Zielscheibe\n4. Punkte zählen', '1. Hang up target\n2. Balls as meteorites\n3. Children throw at the target\n4. Count points', 4, 12, 'both', 'active', 15, 3, ARRAY['Zielscheibe', 'Weiche Bälle'], ARRAY['Target', 'Soft balls'], ARRAY['space', 'superhero']),

-- === SOCCER THEME GAMES ===
('Torwandschiessen', 'Goal Wall Shooting', 'Schiesst den Ball durch die Löcher in der Torwand!', 'Shoot the ball through the holes in the goal wall!', '1. Torwand aufstellen (Pappe mit Löchern)\n2. Abschusslinie markieren\n3. Jedes Kind hat 5 Schüsse\n4. Meiste Treffer gewinnt', '1. Set up goal wall (cardboard with holes)\n2. Mark shooting line\n3. Each child has 5 shots\n4. Most hits wins', 4, 12, 'outdoor', 'active', 20, 3, ARRAY['Torwand (Pappe)', 'Fußball'], ARRAY['Goal wall (cardboard)', 'Soccer ball'], ARRAY['soccer']),

('Dribbel-Parcours', 'Dribble Course', 'Dribbelt den Ball durch den Parcours - Schnellste Zeit gewinnt!', 'Dribble the ball through the course - fastest time wins!', '1. Pylonen als Parcours aufstellen\n2. Stoppuhr bereithalten\n3. Jedes Kind dribbelt durch den Parcours\n4. Schnellste Zeit gewinnt', '1. Set up cones as course\n2. Prepare stopwatch\n3. Each child dribbles through course\n4. Fastest time wins', 5, 12, 'outdoor', 'wild', 20, 3, ARRAY['Pylonen', 'Fußball', 'Stoppuhr'], ARRAY['Cones', 'Soccer ball', 'Stopwatch'], ARRAY['soccer']),

('Elfmeterschiessen', 'Penalty Shootout', 'Wer verwandelt die Meisten Elfmeter?', 'Who scores the most penalties?', '1. Tor aufstellen\n2. Elfmeterpunkt markieren\n3. Jedes Kind schiesst 3 Elfmeter\n4. Torwart wechselt nach jeder Runde\n5. Meiste Tore gewinnt', '1. Set up goal\n2. Mark penalty spot\n3. Each child shoots 3 penalties\n4. Goalkeeper rotates each round\n5. Most goals wins', 5, 12, 'outdoor', 'wild', 20, 3, ARRAY['Tor/Tormarkierung', 'Fußball'], ARRAY['Goal/Goal markers', 'Soccer ball'], ARRAY['soccer']),

('Fußball-Quiz', 'Soccer Quiz', 'Wer weiß am Meisten über Fußball?', 'Who knows the most about soccer?', '1. Quizfragen vorbereiten\n2. Teams bilden\n3. Fragen abwechselnd stellen\n4. Punkte zählen\n5. Gewinnerteam bekommt Preis', '1. Prepare quiz questions\n2. Form teams\n3. Ask questions alternately\n4. Count points\n5. Winning team gets a prize', 6, 12, 'indoor', 'calm', 20, 4, ARRAY['Quizfragen', 'Punkte-Tafel'], ARRAY['Quiz questions', 'Score board'], ARRAY['soccer']),

-- === DETECTIVE THEME GAMES ===
('Tatort-Untersuchung', 'Crime Scene Investigation', 'Untersucht den Tatort und findet die Hinweise!', 'Investigate the crime scene and find the clues!', '1. "Tatort" im Raum aufbauen mit Hinweisen\n2. Kinder bekommen Lupen und Notizblock\n3. Hinweise sammeln und kombinieren\n4. Taeter erraten', '1. Set up "crime scene" in room with clues\n2. Children get magnifying glasses and notepads\n3. Collect and combine clues\n4. Guess the culprit', 6, 12, 'indoor', 'calm', 30, 3, ARRAY['Lupen', 'Notizblöcke', 'Stifte', 'Hinweiskarten', 'Tatort-Requisiten'], ARRAY['Magnifying glasses', 'Notepads', 'Pens', 'Clue cards', 'Crime scene props'], ARRAY['detective']),

('Fingerabdruck-Station', 'Fingerprint Station', 'Nehmt Fingerabdrücke und vergleicht sie!', 'Take fingerprints and compare them!', '1. Stempelkissen und Papier bereitlegen\n2. Jedes Kind drückt seinen Fingerabdruck\n3. Mit Lupe vergleichen\n4. Geheimen Fingerabdruck zuordnen', '1. Prepare ink pads and paper\n2. Each child makes their fingerprint\n3. Compare with magnifying glass\n4. Match the secret fingerprint', 5, 12, 'indoor', 'calm', 15, 3, ARRAY['Stempelkissen', 'Papier', 'Lupen'], ARRAY['Ink pads', 'Paper', 'Magnifying glasses'], ARRAY['detective']),

('Geheimschrift', 'Secret Code', 'Entschlüsselt die Geheimbotschaft!', 'Decode the secret message!', '1. Geheimschrift-Alphabet erstellen (A=1, B=2...)\n2. Verschlüsselte Nachrichten verteilen\n3. Kinder entschlüsseln die Botschaft\n4. Botschaft führt zum Nächsten Hinweis', '1. Create secret alphabet (A=1, B=2...)\n2. Distribute encrypted messages\n3. Children decode the message\n4. Message leads to next clue', 6, 12, 'indoor', 'calm', 20, 3, ARRAY['Code-Tabellen', 'Verschlüsselte Nachrichten', 'Stifte'], ARRAY['Code tables', 'Encrypted messages', 'Pens'], ARRAY['detective', 'pirates']),

('Schatten-Rätsel', 'Shadow Puzzle', 'Welcher Schatten gehört zu welchem Gegenstand?', 'Which shadow belongs to which object?', '1. Verschiedene Gegenstände sammeln\n2. Schatten an die Wand projizieren (Taschenlampe)\n3. Kinder raten welcher Gegenstand den Schatten wirft', '1. Collect various objects\n2. Project shadows on wall (flashlight)\n3. Children guess which object casts the shadow', 4, 10, 'indoor', 'calm', 15, 3, ARRAY['Taschenlampe', 'Verschiedene Gegenstände', 'weiße Wand'], ARRAY['Flashlight', 'Various objects', 'White wall'], ARRAY['detective']),

-- === SUPERHERO THEME GAMES ===
('Superhelden-Training', 'Superhero Training', 'Absolviert das Superhelden-Training und werdet echte Helden!', 'Complete the superhero training and become real heroes!', '1. Hindernisparcours aufbauen\n2. Stationen: Springen, Kriechen, Balancieren, Zielwerfen\n3. Jedes Kind durchläuft den Parcours\n4. Superhelden-Urkunde am Ende', '1. Build obstacle course\n2. Stations: jumping, crawling, balancing, target throwing\n3. Each child runs through the course\n4. Superhero certificate at the end', 4, 12, 'outdoor', 'wild', 25, 3, ARRAY['Pylonen', 'Seile', 'Bälle', 'Tunnel', 'Superhelden-Urkunden'], ARRAY['Cones', 'Ropes', 'Balls', 'Tunnel', 'Superhero certificates'], ARRAY['superhero']),

('Superhelden-Masken', 'Superhero Masks', 'Bastelt eure eigene Superhelden-Maske!', 'Craft your own superhero mask!', '1. Masken-Vorlagen aus Pappe vorbereiten\n2. Farben, Glitzer, Federn bereitlegen\n3. Jedes Kind gestaltet seine eigene Maske\n4. Gummiband befestigen', '1. Prepare mask templates from cardboard\n2. Provide paints, glitter, feathers\n3. Each child designs their own mask\n4. Attach elastic band', 3, 10, 'indoor', 'calm', 25, 3, ARRAY['Masken-Vorlagen', 'Farben', 'Glitzer', 'GummiBänder', 'Federn'], ARRAY['Mask templates', 'Paints', 'Glitter', 'Elastic bands', 'Feathers'], ARRAY['superhero']),

('Kryptonit-Suche', 'Kryptonite Search', 'Findet alle Kryptonit-Steine und rettet die Stadt!', 'Find all kryptonite stones and save the city!', '1. Gruen bemalte Steine im Garten verstecken\n2. Kinder Müssen alle Steine finden\n3. Zeitlimit: 10 Minuten\n4. Alle gefunden = Stadt gerettet!', '1. Hide green painted stones in garden\n2. Children must find all stones\n3. Time limit: 10 minutes\n4. All found = city saved!', 4, 10, 'outdoor', 'active', 15, 3, ARRAY['Gruen bemalte Steine', 'Timer'], ARRAY['Green painted stones', 'Timer'], ARRAY['superhero']),

-- === CIRCUS THEME GAMES ===
('Jonglier-Workshop', 'Juggling Workshop', 'Lernt jonglieren mit Tüchern und Bällen!', 'Learn to juggle with scarves and balls!', '1. Zuerst mit Tüchern ueben (fliegen langsamer)\n2. Dann mit weichen Bällen\n3. Kleine Tricks zeigen\n4. Wer am Längsten jongliert, gewinnt', '1. First practice with scarves (fly slower)\n2. Then with soft balls\n3. Show small tricks\n4. Whoever juggles longest wins', 5, 12, 'both', 'active', 20, 3, ARRAY['JonglierTücher', 'Weiche Bälle'], ARRAY['Juggling scarves', 'Soft balls'], ARRAY['circus']),

('Seiltänzer', 'Tightrope Walker', 'Balanciert über das Seil wie im Zirkus!', 'Balance across the rope like in the circus!', '1. Seil auf den Boden legen\n2. Kinder balancieren darauf\n3. Arme ausbreiten für Balance\n4. Wer ohne Absteigen ans Ende kommt, gewinnt', '1. Place rope on the ground\n2. Children balance on it\n3. Spread arms for balance\n4. Whoever reaches the end without stepping off wins', 3, 10, 'both', 'active', 10, 3, ARRAY['Seil oder Klebeband'], ARRAY['Rope or tape'], ARRAY['circus']),

('Clown-Schminken', 'Clown Face Painting', 'Schminkt euch gegenseitig als Clowns!', 'Paint each others faces as clowns!', '1. Kinderschminke bereitlegen\n2. Spiegel aufstellen\n3. Clown-Vorlagen zeigen\n4. Gegenseitig schminken oder selbst schminken', '1. Prepare face paint\n2. Set up mirrors\n3. Show clown templates\n4. Paint each other or themselves', 3, 10, 'indoor', 'calm', 25, 3, ARRAY['Kinderschminke', 'Spiegel', 'SchminkSchwämme'], ARRAY['Face paint', 'Mirrors', 'Makeup sponges'], ARRAY['circus', 'animals']),

('Teller-Drehen', 'Plate Spinning', 'Dreht den Teller auf dem Stab wie ein Zirkusartist!', 'Spin the plate on the stick like a circus artist!', '1. Plastikteller und Stäbe\n2. Technik zeigen: Teller auf Stab drehen\n3. Kinder ueben\n4. Längstes Drehen gewinnt', '1. Plastic plates and sticks\n2. Show technique: spin plate on stick\n3. Children practice\n4. Longest spin wins', 6, 12, 'both', 'active', 15, 3, ARRAY['Plastikteller', 'Stäbe'], ARRAY['Plastic plates', 'Sticks'], ARRAY['circus']),

-- === KNIGHT THEME GAMES ===
('Ritterturnier', 'Knight Tournament', 'Kämpft mit Poolnudeln und werdet zum Ritter geschlagen!', 'Fight with pool noodles and be knighted!', '1. Poolnudeln als Schwerter\n2. Turnierring markieren\n3. Kämpfe (sanft!) austragen\n4. Gewinner wird zum Ritter geschlagen', '1. Pool noodles as swords\n2. Mark tournament ring\n3. Fights (gentle!) take place\n4. Winner is knighted', 5, 12, 'outdoor', 'wild', 20, 4, ARRAY['Poolnudeln', 'Kreide für Ring'], ARRAY['Pool noodles', 'Chalk for ring'], ARRAY['knight']),

('Burgenbau', 'Castle Building', 'Baut die größte und stabilste Burg aus Kartons!', 'Build the biggest and sturdiest castle from boxes!', '1. Kartons und Klebeband verteilen\n2. Teams bilden\n3. 20 Minuten Bauzeit\n4. schönste/größte Burg gewinnt', '1. Distribute boxes and tape\n2. Form teams\n3. 20 minutes building time\n4. Most beautiful/biggest castle wins', 4, 12, 'both', 'calm', 25, 4, ARRAY['Kartons', 'Klebeband', 'Scheren', 'Farbe'], ARRAY['Boxes', 'Tape', 'Scissors', 'Paint'], ARRAY['knight']),

('Schild-Basteln', 'Shield Crafting', 'Bastelt euer eigenes Ritterschild!', 'Craft your own knight shield!', '1. Pappe als Schildform zuschneiden\n2. Griff auf die Rückseite kleben\n3. Vorderseite mit Wappen bemalen\n4. Trocknen lassen und benutzen', '1. Cut cardboard into shield shape\n2. Glue handle on the back\n3. Paint coat of arms on front\n4. Let dry and use', 4, 10, 'indoor', 'calm', 25, 3, ARRAY['Pappe', 'Farbe', 'Kleber', 'Griffe (Streifen)'], ARRAY['Cardboard', 'Paint', 'Glue', 'Handles (strips)'], ARRAY['knight']),

-- === MERMAID THEME GAMES ===
('Unterwasser-Schatzsuche', 'Underwater Treasure Hunt', 'Taucht ab und findet die versunkenen Schätze!', 'Dive in and find the sunken treasures!', '1. Raum mit blauen Tüchern dekorieren (Meer)\n2. Glitzersteine und Muscheln verstecken\n3. Kinder "tauchen" (kriechen) und suchen\n4. Meiste Schätze gewinnt', '1. Decorate room with blue cloths (sea)\n2. Hide glitter stones and shells\n3. Children "dive" (crawl) and search\n4. Most treasures wins', 3, 8, 'indoor', 'active', 20, 3, ARRAY['Blaue Tücher', 'Glitzersteine', 'Muscheln'], ARRAY['Blue cloths', 'Glitter stones', 'Shells'], ARRAY['mermaid']),

('Muschel-Staffel', 'Shell Relay', 'Transportiert die Muscheln im Löffel zum Ziel!', 'Transport the shells on spoons to the finish!', '1. Start- und Ziellinie markieren\n2. Muscheln auf Löffel balancieren\n3. Staffellauf: Nächstes Kind übernimmt\n4. Schnellstes Team gewinnt', '1. Mark start and finish lines\n2. Balance shells on spoons\n3. Relay: next child takes over\n4. Fastest team wins', 4, 10, 'outdoor', 'active', 15, 4, ARRAY['Muscheln', 'Löffel', 'Eimer'], ARRAY['Shells', 'Spoons', 'Buckets'], ARRAY['mermaid', 'pirates']),

('Meerjungfrauen-Kronen', 'Mermaid Crowns', 'Bastelt wunderSchöne Meerjungfrauen-Kronen!', 'Craft beautiful mermaid crowns!', '1. Kronenform aus Pappe schneiden\n2. Mit Muscheln, Perlen, Glitzer dekorieren\n3. Gummiband befestigen\n4. Krönung!', '1. Cut crown shape from cardboard\n2. Decorate with shells, pearls, glitter\n3. Attach elastic band\n4. Coronation!', 3, 8, 'indoor', 'calm', 25, 3, ARRAY['Pappe', 'Muscheln', 'Perlen', 'Glitzer', 'Kleber', 'GummiBänder'], ARRAY['Cardboard', 'Shells', 'Pearls', 'Glitter', 'Glue', 'Elastic bands'], ARRAY['mermaid', 'princess']),

-- === JUNGLE THEME GAMES ===
('Dschungel-Expedition', 'Jungle Expedition', 'Geht auf Dschungel-Expedition und findet die wilden Tiere!', 'Go on a jungle expedition and find the wild animals!', '1. Tierfiguren im Garten/Raum verstecken\n2. Kinder bekommen eine Checkliste\n3. Alle Tiere auf der Liste finden\n4. Vollstaendige Liste = Preis', '1. Hide animal figures in garden/room\n2. Children get a checklist\n3. Find all animals on the list\n4. Complete list = prize', 3, 10, 'both', 'active', 25, 3, ARRAY['Tierfiguren', 'Checklisten', 'Stifte'], ARRAY['Animal figures', 'Checklists', 'Pens'], ARRAY['jungle', 'animals']),

('Affenklettern', 'Monkey Climbing', 'Klettert wie die Affen durch den Parcours!', 'Climb like monkeys through the course!', '1. Hindernisparcours aufbauen\n2. Unter Seilen durchkriechen\n3. über Kissen klettern\n4. Bananen (Plastik) am Ende sammeln', '1. Build obstacle course\n2. Crawl under ropes\n3. Climb over cushions\n4. Collect bananas (plastic) at the end', 4, 10, 'outdoor', 'wild', 20, 3, ARRAY['Seile', 'Kissen', 'Plastik-Bananen'], ARRAY['Ropes', 'Cushions', 'Plastic bananas'], ARRAY['jungle', 'animals']),

('Schlangen-Rennen', 'Snake Race', 'Bildet eine Schlange und rennt zum Ziel!', 'Form a snake and race to the finish!', '1. Teams bilden\n2. Hintereinander aufstellen und festhalten\n3. Als Schlange zum Ziel laufen\n4. Wer zuerst ankommt, gewinnt', '1. Form teams\n2. Line up and hold on\n3. Run as a snake to the finish\n4. First to arrive wins', 4, 10, 'outdoor', 'wild', 10, 6, ARRAY['Markierung für Start/Ziel'], ARRAY['Markers for start/finish'], ARRAY['jungle', 'animals']),

('TierGeräusche-Quiz', 'Animal Sounds Quiz', 'Erkennt die TierGeräusche!', 'Identify the animal sounds!', '1. TierGeräusche auf dem Handy vorbereiten\n2. Nacheinander abspielen\n3. Kinder raten welches Tier\n4. Meiste richtige Antworten gewinnt', '1. Prepare animal sounds on phone\n2. Play one by one\n3. Children guess which animal\n4. Most correct answers wins', 3, 8, 'indoor', 'calm', 15, 3, ARRAY['Handy mit TierGeräusche-App'], ARRAY['Phone with animal sounds app'], ARRAY['jungle', 'animals']),

-- === ANIMAL THEME GAMES ===
('Tiermasken-Basteln', 'Animal Mask Crafting', 'Bastelt eure eigene Tiermaske!', 'Craft your own animal mask!', '1. Papierteller als Basis\n2. AugenLöcher schneiden\n3. Mit Farbe, Federn, Fell bemalen/bekleben\n4. Stab oder Gummiband befestigen', '1. Paper plates as base\n2. Cut eye holes\n3. Paint/glue with paint, feathers, fur\n4. Attach stick or elastic band', 3, 10, 'indoor', 'calm', 25, 3, ARRAY['Papierteller', 'Farbe', 'Federn', 'Kunstfell', 'GummiBänder'], ARRAY['Paper plates', 'Paint', 'Feathers', 'Faux fur', 'Elastic bands'], ARRAY['animals', 'jungle']),

('Tier-Pantomime', 'Animal Charades', 'Stellt Tiere pantomimisch dar und lasst die anderen raten!', 'Act out animals and let others guess!', '1. Tierkarten vorbereiten\n2. Ein Kind zieht eine Karte\n3. Tier ohne Worte darstellen\n4. Andere raten\n5. Wer richtig raet, ist als Nächstes dran', '1. Prepare animal cards\n2. One child draws a card\n3. Act out the animal without words\n4. Others guess\n5. Correct guesser goes next', 4, 12, 'both', 'active', 15, 4, ARRAY['Tierkarten'], ARRAY['Animal cards'], ARRAY['animals', 'circus', 'jungle']),

-- === ADDITIONAL GAMES FOR VARIETY ===
('Dosenwerfen', 'Tin Can Bowling', 'Werft die Dosen um und sammelt Punkte!', 'Knock down the cans and collect points!', '1. 10 Dosen pyramidenförmig aufstellen\n2. Wurflinie markieren (2-3m Abstand)\n3. Jedes Kind hat 3 Wuerfe\n4. Umgeworfene Dosen zählen', '1. Stack 10 cans in pyramid\n2. Mark throwing line (2-3m distance)\n3. Each child has 3 throws\n4. Count knocked down cans', 3, 12, 'both', 'active', 15, 3, ARRAY['10 leere Dosen', 'Bälle (weich)'], ARRAY['10 empty cans', 'Balls (soft)'], ARRAY['no-theme', 'pirates', 'circus']),

('Schoko-Pudding-Wettessen', 'Pudding Eating Contest', 'Wer isst den Pudding am Schnellsten - ohne Hände!', 'Who eats the pudding fastest - no hands!', '1. Schokopudding in Schüssel pro Kind\n2. Hände auf den Rücken\n3. Auf Kommando: Pudding essen nur mit dem Mund\n4. Wer zuerst fertig ist, gewinnt', '1. Chocolate pudding in bowl per child\n2. Hands behind back\n3. On command: eat pudding with mouth only\n4. First to finish wins', 4, 12, 'outdoor', 'active', 10, 3, ARRAY['Schokopudding', 'Schüsseln', 'Lappen zum Abwischen'], ARRAY['Chocolate pudding', 'Bowls', 'Cloths for wiping'], ARRAY['no-theme']),

('Ballon-Platzen', 'Balloon Pop', 'Platzt den Ballon des Gegners, schützt euren eigenen!', 'Pop the opponents balloon, protect your own!', '1. Jedem Kind einen Luftballon ans Bein binden\n2. Musik abspielen\n3. Versuchen, die Ballons der anderen zu zertreten\n4. Eigenen Ballon Schützen\n5. Letzter Ballon gewinnt', '1. Tie a balloon to each child leg\n2. Play music\n3. Try to stomp on others balloons\n4. Protect your own balloon\n5. Last balloon wins', 5, 12, 'outdoor', 'wild', 15, 4, ARRAY['Luftballons', 'Schnur', 'Musikbox'], ARRAY['Balloons', 'String', 'Speaker'], ARRAY['no-theme', 'superhero']),

('Schnitzeljagd', 'Scavenger Hunt', 'Folgt den Hinweisen quer durch den Garten!', 'Follow the clues across the garden!', '1. 8-10 Hinweise an verschiedenen Orten verstecken\n2. Jeder Hinweis führt zum Nächsten\n3. Letzter Hinweis führt zum Schatz\n4. Gemeinsam lösen', '1. Hide 8-10 clues at various locations\n2. Each clue leads to the next\n3. Last clue leads to treasure\n4. Solve together', 5, 12, 'outdoor', 'active', 30, 3, ARRAY['Hinweiszettel', 'Schatz', 'Stifte'], ARRAY['Clue notes', 'Treasure', 'Pens'], ARRAY['no-theme', 'pirates', 'detective', 'jungle']),

('Wattepusten', 'Cotton Ball Blow', 'Pustet den Wattebausch über den Tisch - wer ist zuerst am Ziel?', 'Blow the cotton ball across the table - who finishes first?', '1. Wattebäusche auf den Tisch\n2. Ziellinie am Tischende markieren\n3. Pusten!\n4. Wer zuerst den Wattebausch übers Ziel pustet, gewinnt', '1. Cotton balls on the table\n2. Mark finish line at table edge\n3. Blow!\n4. First to blow cotton ball past finish wins', 3, 8, 'indoor', 'calm', 10, 3, ARRAY['Wattebäusche', 'Tisch'], ARRAY['Cotton balls', 'Table'], ARRAY['no-theme']),

('Zeitungstanz', 'Newspaper Dance', 'Tanzt auf der Zeitung - sie wird immer kleiner!', 'Dance on the newspaper - it keeps getting smaller!', '1. Jedes Kind steht auf einer doppelten Zeitungsseite\n2. Musik an: tanzen\n3. Musik aus: zurück auf die Zeitung\n4. Zeitung einmal falten\n5. Wer nicht mehr draufpasst, scheidet aus', '1. Each child stands on a double newspaper page\n2. Music on: dance\n3. Music off: back on the newspaper\n4. Fold newspaper once\n5. Whoever cant fit anymore is out', 4, 10, 'indoor', 'active', 15, 3, ARRAY['Zeitungen', 'Musikbox'], ARRAY['Newspapers', 'Speaker'], ARRAY['no-theme', 'circus']),

('Fischer, Fischer, wie tief ist das Wasser?', 'Red Light Green Light', 'Der Fischer ruft und alle Müssen auf seine Art überqueren!', 'The fisher calls and everyone must cross in their style!', '1. Ein Kind ist der Fischer auf der anderen Seite\n2. Kinder rufen: "Fischer, Fischer, wie tief ist das Wasser?"\n3. Fischer antwortet und bestimmt Fortbewegungsart\n4. Kinder überqueren, Fischer versucht zu fangen', '1. One child is the fisher on the other side\n2. Children call out the question\n3. Fisher answers and determines movement type\n4. Children cross, fisher tries to catch', 4, 10, 'outdoor', 'wild', 15, 5, ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY['no-theme', 'mermaid', 'pirates']),

('Flaschendrehen', 'Spin the Bottle', 'Dreht die Flasche und erfuellt lustige Aufgaben!', 'Spin the bottle and complete funny tasks!', '1. Im Kreis sitzen\n2. Flasche drehen\n3. Auf wen sie zeigt, zieht eine Aufgabenkarte\n4. Aufgabe Ausführen (z.B. 10 Hampelmänner, TierGeräusch machen)', '1. Sit in a circle\n2. Spin the bottle\n3. Whoever it points to draws a task card\n4. Complete the task (e.g. 10 jumping jacks, make animal sound)', 4, 10, 'indoor', 'active', 15, 4, ARRAY['Flasche', 'Aufgabenkarten'], ARRAY['Bottle', 'Task cards'], ARRAY['no-theme']),

('Schatzinsel-Hopping', 'Treasure Island Hopping', 'Springt von Insel zu Insel und sammelt Schätze!', 'Jump from island to island and collect treasures!', '1. Teppichstücke als Inseln auslegen\n2. Goldmünzen auf manchen Inseln\n3. Von Insel zu Insel springen\n4. Schätze einsammeln\n5. Meiste Schätze gewinnt', '1. Lay out carpet pieces as islands\n2. Gold coins on some islands\n3. Jump from island to island\n4. Collect treasures\n5. Most treasures wins', 3, 8, 'indoor', 'active', 15, 3, ARRAY['Teppichstücke', 'SchokoMünzen'], ARRAY['Carpet pieces', 'Chocolate coins'], ARRAY['pirates', 'mermaid']),

('Hindernislauf', 'Obstacle Course', 'Bezwingt den Hindernisparcours!', 'Conquer the obstacle course!', '1. Parcours mit Stühlen, Seilen, Kisten aufbauen\n2. Drüber, drunter, drumherum\n3. Zeit stoppen\n4. Schnellste Zeit gewinnt', '1. Build course with chairs, ropes, boxes\n2. Over, under, around\n3. Time each run\n4. Fastest time wins', 4, 12, 'both', 'wild', 20, 3, ARRAY['Stühle', 'Seile', 'Kisten', 'Stoppuhr'], ARRAY['Chairs', 'Ropes', 'Boxes', 'Stopwatch'], ARRAY['no-theme', 'superhero', 'knight']),

('Wasserbomben-Werfen', 'Water Balloon Toss', 'Werft die Wasserbomben und bleibt trocken!', 'Toss water balloons and stay dry!', '1. Wasserbomben fuellen\n2. Paare bilden\n3. Zuwerfen und fangen\n4. Nach jeder Runde einen Schritt zurück\n5. Letztes Paar ohne Platzer gewinnt', '1. Fill water balloons\n2. Form pairs\n3. Toss and catch\n4. Step back after each round\n5. Last pair without burst wins', 4, 12, 'outdoor', 'active', 15, 4, ARRAY['Wasserbomben', 'Wasserhahn'], ARRAY['Water balloons', 'Water tap'], ARRAY['no-theme', 'pirates', 'mermaid']),

('Pantomime-Raten', 'Charades', 'Stellt Begriffe pantomimisch dar!', 'Act out words without speaking!', '1. Begriffe auf Karten schreiben\n2. Ein Kind zieht eine Karte\n3. Begriff ohne Worte darstellen\n4. Andere raten\n5. Wer richtig raet, ist dran', '1. Write words on cards\n2. One child draws a card\n3. Act out the word without speaking\n4. Others guess\n5. Correct guesser goes next', 5, 12, 'both', 'active', 20, 4, ARRAY['Begriffskarten'], ARRAY['Word cards'], ARRAY['no-theme', 'circus']),

('Malwettbewerb', 'Drawing Contest', 'Malt das schönste Bild zum Thema!', 'Draw the best picture on the topic!', '1. Thema vorgeben (passt zum Motto)\n2. Papier und Stifte verteilen\n3. 10 Minuten Malzeit\n4. Alle Bilder ausstellen\n5. Abstimmung über das schönste Bild', '1. Set topic (matching the theme)\n2. Distribute paper and pens\n3. 10 minutes drawing time\n4. Display all pictures\n5. Vote for the best picture', 3, 12, 'indoor', 'calm', 15, 3, ARRAY['Papier', 'Buntstifte', 'Filzstifte'], ARRAY['Paper', 'Colored pencils', 'Markers'], ARRAY['no-theme', 'dinosaurs', 'space', 'animals']),

('Gummibärchen-Wettessen', 'Gummy Bear Race', 'Wer isst die Meisten Gummibärchen mit Stäbchen?', 'Who can eat the most gummy bears with chopsticks?', '1. Gummibärchen in Schüssel pro Kind\n2. Jedes Kind bekommt Stäbchen\n3. 1 Minute Zeit\n4. Nur mit Stäbchen essen\n5. Meiste Bärchen gewinnt', '1. Gummy bears in bowl per child\n2. Each child gets chopsticks\n3. 1 minute time\n4. Only eat with chopsticks\n5. Most bears wins', 5, 12, 'indoor', 'calm', 10, 3, ARRAY['Gummibärchen', 'Stäbchen', 'Schüsseln', 'Timer'], ARRAY['Gummy bears', 'Chopsticks', 'Bowls', 'Timer'], ARRAY['no-theme']),

('Limbotanzen', 'Limbo Dance', 'Wie tief könnt ihr euch unter der Stange durchbiegen?', 'How low can you go under the bar?', '1. Stange oder Besenstiel waagerecht halten\n2. Kinder gehen einzeln drunter durch\n3. Nach jeder Runde die Stange tiefer\n4. Wer den Boden berührt oder die Stange, ist raus', '1. Hold bar or broom handle horizontally\n2. Children pass under one at a time\n3. Lower the bar after each round\n4. Touching floor or bar means out', 4, 12, 'both', 'active', 15, 3, ARRAY['Besenstiel oder Stange', 'Musikbox'], ARRAY['Broom handle or bar', 'Speaker'], ARRAY['no-theme', 'circus', 'jungle']),

('Hula-Hoop-Challenge', 'Hula Hoop Challenge', 'Wer kann am Längsten den Hula-Hoop drehen?', 'Who can spin the hula hoop the longest?', '1. Hula-Hoops verteilen\n2. Auf Kommando starten\n3. Wer den Hoop fallen lässt, ist raus\n4. Längstes Drehen gewinnt', '1. Distribute hula hoops\n2. Start on command\n3. Whoever drops the hoop is out\n4. Longest spin wins', 4, 12, 'both', 'active', 10, 3, ARRAY['Hula-Hoops'], ARRAY['Hula hoops'], ARRAY['no-theme', 'circus']),

('Geheime-Mission', 'Secret Mission', 'Erfuellt die geheime Mission bevor die Zeit abläuft!', 'Complete the secret mission before time runs out!', '1. MissionsUmschläge mit Aufgaben verteilen\n2. Teams lösen Rätsel und Aufgaben\n3. Jede gelöste Aufgabe gibt einen Hinweis\n4. Alle Hinweise zusammen lösen das Große Rätsel', '1. Distribute mission envelopes with tasks\n2. Teams solve puzzles and tasks\n3. Each solved task gives a clue\n4. All clues together solve the big puzzle', 6, 12, 'both', 'active', 30, 4, ARRAY['Umschläge', 'Aufgabenkarten', 'Stifte', 'Rätsel'], ARRAY['Envelopes', 'Task cards', 'Pens', 'Puzzles'], ARRAY['detective', 'space', 'superhero']),

('Piñata', 'Pinata', 'Schlagt die Piñata und sammelt die Süßigkeiten!', 'Hit the pinata and collect the sweets!', '1. Piñata aufhaengen\n2. Kinder werden der Reihe nach verbunden\n3. Mit Stock auf die Piñata schlagen\n4. Süßigkeiten aufsammeln', '1. Hang up pinata\n2. Children are blindfolded in turn\n3. Hit the pinata with stick\n4. Collect sweets', 3, 12, 'outdoor', 'wild', 15, 3, ARRAY['Piñata', 'Stock', 'Augenbinde', 'Süßigkeiten'], ARRAY['Pinata', 'Stick', 'Blindfold', 'Sweets'], ARRAY['no-theme', 'jungle', 'circus']),

('Tauziehen', 'Tug of War', 'Welches Team ist stärker?', 'Which team is stronger?', '1. Langes, dickes Seil\n2. Mittelpunkt markieren\n3. Zwei gleichGroße Teams\n4. Auf Kommando ziehen\n5. Wer das andere Team über die Linie zieht, gewinnt', '1. Long, thick rope\n2. Mark center point\n3. Two equal teams\n4. Pull on command\n5. Team that pulls the other over the line wins', 5, 12, 'outdoor', 'wild', 10, 6, ARRAY['Dickes Seil', 'Kreide'], ARRAY['Thick rope', 'Chalk'], ARRAY['no-theme', 'pirates', 'knight', 'superhero']),

('Schützenkoenig', 'Sharpshooter', 'Wer trifft am besten mit dem Bogen?', 'Who has the best aim with the bow?', '1. Zielscheibe aufstellen\n2. Kinderbogen oder Saugnapf-Pfeile\n3. Jedes Kind hat 5 Schüsse\n4. Punkte zählen\n5. Meiste Punkte gewinnt', '1. Set up target\n2. Children bow or suction cup arrows\n3. Each child has 5 shots\n4. Count points\n5. Most points wins', 6, 12, 'outdoor', 'active', 20, 3, ARRAY['Kinderbogen', 'Saugnapf-Pfeile', 'Zielscheibe'], ARRAY['Children bow', 'Suction cup arrows', 'Target'], ARRAY['knight', 'no-theme']),

('Verstecken', 'Hide and Seek', 'Der Klassiker - wer findet das beste Versteck?', 'The classic - who finds the best hiding spot?', '1. Ein Kind zaehlt bis 30 mit geschlossenen Augen\n2. Andere verstecken sich\n3. Sucher muss alle finden\n4. Wer zuletzt gefunden wird, zaehlt als Nächstes', '1. One child counts to 30 with closed eyes\n2. Others hide\n3. Seeker must find everyone\n4. Last one found counts next', 3, 12, 'both', 'active', 20, 4, ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY['no-theme', 'detective', 'jungle']),

('Würfelspiel', 'Dice Game', 'Würfelt und erfuellt die Aufgabe!', 'Roll the dice and complete the task!', '1. Würfel mit Aufgaben auf jeder Seite\n2. Reihum Würfeln\n3. Aufgabe Ausführen (Hampelmann, TierGeräusch, Lied singen...)\n4. Spaß haben!', '1. Dice with tasks on each side\n2. Take turns rolling\n3. Complete task (jumping jacks, animal sound, sing a song...)\n4. Have fun!', 3, 8, 'indoor', 'active', 15, 3, ARRAY['Großer Würfel', 'Aufgabenliste'], ARRAY['Large dice', 'Task list'], ARRAY['no-theme', 'circus']),

('Seifenblasen-Wettbewerb', 'Bubble Contest', 'Wer macht die größte Seifenblase?', 'Who makes the biggest bubble?', '1. Seifenblasen-Loesung vorbereiten\n2. Verschiedene Stab-Groessen\n3. größte Blase messen\n4. Oder: Meiste Blasen in 30 Sekunden', '1. Prepare bubble solution\n2. Various wand sizes\n3. Measure biggest bubble\n4. Or: most bubbles in 30 seconds', 3, 8, 'outdoor', 'calm', 15, 3, ARRAY['Seifenblasen-Loesung', 'Verschiedene Stäbe/Ringe'], ARRAY['Bubble solution', 'Various wands/rings'], ARRAY['no-theme', 'unicorn', 'mermaid']),

('Stelzenlauf', 'Stilt Walk', 'Lauft auf Dosenstelzen zum Ziel!', 'Walk on tin can stilts to the finish!', '1. Dosenstelzen vorbereiten (Dosen mit Schnur)\n2. Startlinie markieren\n3. Balance halten und laufen\n4. Wer zuerst ankommt, gewinnt', '1. Prepare tin can stilts (cans with string)\n2. Mark start line\n3. Keep balance and walk\n4. First to arrive wins', 4, 10, 'outdoor', 'active', 15, 3, ARRAY['Dosenstelzen', 'Kreide'], ARRAY['Tin can stilts', 'Chalk'], ARRAY['no-theme', 'circus']),

('Farbenlauf', 'Color Run', 'Lauft zur richtigen Farbe, wenn sie aufgerufen wird!', 'Run to the right color when it is called!', '1. Farbige Tüchern/Karten im Raum verteilen\n2. Eine Farbe rufen\n3. Alle Kinder laufen zur richtigen Farbe\n4. Letztes Kind bei der Farbe scheidet aus', '1. Distribute colored cloths/cards around room\n2. Call a color\n3. All children run to the right color\n4. Last child at the color is out', 3, 7, 'both', 'wild', 10, 4, ARRAY['Farbige Tücher oder Karten'], ARRAY['Colored cloths or cards'], ARRAY['no-theme', 'unicorn']);


-- ============================================================
-- RECIPES (14 Mottos - one cake per theme)
-- ============================================================
INSERT INTO public.recipes (theme_slug, name_de, name_en, description_de, description_en, instructions_de, instructions_en, servings, prep_time_minutes, ingredients_de, ingredients_en, is_nut_free) VALUES
('pirates', 'Piratenschiff-Kuchen', 'Pirate Ship Cake', 'Ein beeindruckender Kuchen in Form eines Piratenschiffs.', 'An impressive cake shaped like a pirate ship.', '1. Schokoladenkuchen in Kastenform backen\n2. Abkuehlen lassen und in Schiffsform schneiden\n3. Mit Schokoladenglasur überziehen\n4. Papier-Segel auf Holzspiesse stecken\n5. Gummibärchen als Piraten dekorieren\n6. Blaue Götterspeise als Meer drumherum', '1. Bake chocolate cake in loaf pan\n2. Let cool and cut into ship shape\n3. Cover with chocolate glaze\n4. Put paper sails on wooden skewers\n5. Decorate with gummy bears as pirates\n6. Blue jelly as sea around it', 12, 90, '[{"item": "Schokoladenkuchen-Mischung", "amount": "1 Packung"}, {"item": "Schokoladenglasur", "amount": "200g"}, {"item": "Holzspiesse", "amount": "3"}, {"item": "Papier für Segel", "amount": "3 Blaetter"}, {"item": "Gummibärchen", "amount": "1 Tuete"}, {"item": "Goetterspeise blau", "amount": "2 Packungen"}]', '[{"item": "Chocolate cake mix", "amount": "1 box"}, {"item": "Chocolate glaze", "amount": "200g"}, {"item": "Wooden skewers", "amount": "3"}, {"item": "Paper for sails", "amount": "3 sheets"}, {"item": "Gummy bears", "amount": "1 bag"}, {"item": "Blue jelly", "amount": "2 packages"}]', true),

('princess', 'Kroenen-Kuchen', 'Crown Cake', 'Ein majestaetischer Kuchen mit goldener Krone.', 'A majestic cake with a golden crown.', '1. Runden Vanillekuchen backen\n2. Mit rosa Buttercreme einstreichen\n3. Goldene Zuckerperlen verzieren\n4. Krone aus Fondant formen\n5. Auf den Kuchen setzen\n6. Essbare Glitzerstreusel verteilen', '1. Bake round vanilla cake\n2. Spread with pink buttercream\n3. Decorate with golden sugar pearls\n4. Shape crown from fondant\n5. Place on cake\n6. Distribute edible glitter sprinkles', 12, 75, '[{"item": "Vanillekuchen-Mischung", "amount": "1 Packung"}, {"item": "Buttercreme (rosa)", "amount": "300g"}, {"item": "Fondant (gold)", "amount": "100g"}, {"item": "Goldene Zuckerperlen", "amount": "50g"}, {"item": "Essbare Glitzerstreusel", "amount": "30g"}]', '[{"item": "Vanilla cake mix", "amount": "1 box"}, {"item": "Buttercream (pink)", "amount": "300g"}, {"item": "Fondant (gold)", "amount": "100g"}, {"item": "Golden sugar pearls", "amount": "50g"}, {"item": "Edible glitter sprinkles", "amount": "30g"}]', true),

('dinosaurs', 'Vulkan-Kuchen', 'Volcano Cake', 'Ein dramatischer Vulkan-Kuchen der ausbricht!', 'A dramatic volcano cake that erupts!', '1. Gugelhupf-Kuchen backen (für die Vulkanform)\n2. Mit brauner und gruener Glasur überziehen\n3. Loch in der Mitte für rote Glasur (Lava)\n4. Dino-Figuren um den Vulkan platzieren\n5. Rote Glasur runterlaufen lassen', '1. Bake bundt cake (for volcano shape)\n2. Cover with brown and green glaze\n3. Hole in center for red glaze (lava)\n4. Place dino figures around volcano\n5. Let red glaze drip down', 12, 60, '[{"item": "Kuchen-Mischung", "amount": "1 Packung"}, {"item": "Glasur braun", "amount": "150g"}, {"item": "Glasur gruen", "amount": "100g"}, {"item": "Glasur rot", "amount": "100g"}, {"item": "Dino-Figuren (Plastik)", "amount": "5"}]', '[{"item": "Cake mix", "amount": "1 box"}, {"item": "Brown glaze", "amount": "150g"}, {"item": "Green glaze", "amount": "100g"}, {"item": "Red glaze", "amount": "100g"}, {"item": "Dino figures (plastic)", "amount": "5"}]', true),

('space', 'Galaxie-Kuchen', 'Galaxy Cake', 'Ein kosmischer Kuchen mit Sternen und Planeten!', 'A cosmic cake with stars and planets!', '1. Schokoladenkuchen backen\n2. Schwarze Glasur auftragen\n3. Lila, blaue und pinke Lebensmittelfarbe marmorieren\n4. Silberne Zuckerstreusel als Sterne\n5. Planeten aus Fondant formen\n6. Optional: Wunderkerzen zum Servieren', '1. Bake chocolate cake\n2. Apply black glaze\n3. Marble with purple, blue and pink food coloring\n4. Silver sugar sprinkles as stars\n5. Shape planets from fondant\n6. Optional: sparklers for serving', 12, 90, '[{"item": "Schokoladenkuchen-Mischung", "amount": "1 Packung"}, {"item": "Schwarze Glasur", "amount": "200g"}, {"item": "Lebensmittelfarbe (lila, blau, pink)", "amount": "je 1"}, {"item": "Silberne Zuckerstreusel", "amount": "50g"}, {"item": "Fondant (bunt)", "amount": "150g"}]', '[{"item": "Chocolate cake mix", "amount": "1 box"}, {"item": "Black glaze", "amount": "200g"}, {"item": "Food coloring (purple, blue, pink)", "amount": "1 each"}, {"item": "Silver sugar sprinkles", "amount": "50g"}, {"item": "Fondant (colorful)", "amount": "150g"}]', true),

('soccer', 'Fußball-Kuchen', 'Soccer Ball Cake', 'Ein runder Kuchen der aussieht wie ein Fußball!', 'A round cake that looks like a soccer ball!', '1. Runden Kuchen backen\n2. weiße Glasur auftragen\n3. Schwarze Fondant-Fuenfecke formen\n4. Auf den Kuchen als Fußballmuster legen\n5. Gruene Kokosflocken als Rasen drumherum', '1. Bake round cake\n2. Apply white glaze\n3. Shape black fondant pentagons\n4. Place on cake as soccer pattern\n5. Green coconut flakes as grass around it', 12, 75, '[{"item": "Kuchen-Mischung", "amount": "1 Packung"}, {"item": "weiße Glasur", "amount": "200g"}, {"item": "Schwarzer Fondant", "amount": "100g"}, {"item": "Kokosflocken", "amount": "50g"}, {"item": "Gruene Lebensmittelfarbe", "amount": "1"}]', '[{"item": "Cake mix", "amount": "1 box"}, {"item": "White glaze", "amount": "200g"}, {"item": "Black fondant", "amount": "100g"}, {"item": "Coconut flakes", "amount": "50g"}, {"item": "Green food coloring", "amount": "1"}]', true),

('detective', 'Lupe-Kuchen', 'Magnifying Glass Cake', 'Ein geheimnisvoller Kuchen in Form einer Lupe!', 'A mysterious cake shaped like a magnifying glass!', '1. Runden Kuchen backen (LupenKörper)\n2. Laenglichen Kuchen für den Griff\n3. Zusammensetzen\n4. Mit brauner Glasur (Griff) und durchsichtiger Gelee-Glasur (Glas) überziehen\n5. Fingerabdruck aus Fondant als Deko', '1. Bake round cake (lens body)\n2. Rectangular cake for handle\n3. Assemble\n4. Cover with brown glaze (handle) and transparent jelly glaze (glass)\n5. Fondant fingerprint as decoration', 12, 90, '[{"item": "Kuchen-Mischung", "amount": "2 Packungen"}, {"item": "Braune Glasur", "amount": "200g"}, {"item": "Transparentes Gelee", "amount": "1 Packung"}, {"item": "Fondant (braun)", "amount": "100g"}]', '[{"item": "Cake mix", "amount": "2 boxes"}, {"item": "Brown glaze", "amount": "200g"}, {"item": "Transparent jelly", "amount": "1 package"}, {"item": "Fondant (brown)", "amount": "100g"}]', true),

('unicorn', 'Einhorn-Kuchen', 'Unicorn Cake', 'Ein magischer Kuchen mit Regenbogenfarben und Einhornhorn!', 'A magical cake with rainbow colors and unicorn horn!', '1. Vanillekuchen backen\n2. Mit pastellfarbener Buttercreme einstreichen\n3. Einhornhorn aus goldenem Fondant drehen\n4. Ohren und Blumen aus Fondant\n5. Regenbogen-Streusel verteilen\n6. Essbare Blumen dekorieren', '1. Bake vanilla cake\n2. Spread with pastel buttercream\n3. Twist unicorn horn from golden fondant\n4. Ears and flowers from fondant\n5. Distribute rainbow sprinkles\n6. Decorate with edible flowers', 12, 90, '[{"item": "Vanillekuchen-Mischung", "amount": "1 Packung"}, {"item": "Buttercreme (pastell)", "amount": "400g"}, {"item": "Fondant (gold)", "amount": "100g"}, {"item": "Fondant (bunt)", "amount": "100g"}, {"item": "Regenbogen-Streusel", "amount": "50g"}, {"item": "Essbare Blumen", "amount": "1 Packung"}]', '[{"item": "Vanilla cake mix", "amount": "1 box"}, {"item": "Buttercream (pastel)", "amount": "400g"}, {"item": "Fondant (gold)", "amount": "100g"}, {"item": "Fondant (colorful)", "amount": "100g"}, {"item": "Rainbow sprinkles", "amount": "50g"}, {"item": "Edible flowers", "amount": "1 package"}]', true),

('animals', 'Bauernhof-Kuchen', 'Farm Cake', 'Ein niedlicher Kuchen mit BauernhofTieren!', 'A cute cake with farm animals!', '1. Rechteckigen Kuchen backen\n2. Gruene Glasur als Wiese\n3. Zaun aus Schokoriegeln\n4. Tierfiguren aus Fondant oder Plastik platzieren\n5. Streusel als Heu', '1. Bake rectangular cake\n2. Green glaze as meadow\n3. Fence from chocolate bars\n4. Place animal figures from fondant or plastic\n5. Sprinkles as hay', 12, 60, '[{"item": "Kuchen-Mischung", "amount": "1 Packung"}, {"item": "Gruene Glasur", "amount": "200g"}, {"item": "Schokoriegel (duenn)", "amount": "8"}, {"item": "Tierfiguren", "amount": "6"}, {"item": "Streusel", "amount": "30g"}]', '[{"item": "Cake mix", "amount": "1 box"}, {"item": "Green glaze", "amount": "200g"}, {"item": "Thin chocolate bars", "amount": "8"}, {"item": "Animal figures", "amount": "6"}, {"item": "Sprinkles", "amount": "30g"}]', true),

('superhero', 'Superhelden-Kuchen', 'Superhero Cake', 'Ein kraftvoller Kuchen mit Superhelden-Logo!', 'A powerful cake with superhero logo!', '1. Runden Kuchen backen\n2. Rote und blaue Glasur auftragen\n3. Blitz oder Stern aus gelbem Fondant\n4. POW! und BAM! Schriftzuege aus Fondant\n5. Bunte Streusel verteilen', '1. Bake round cake\n2. Apply red and blue glaze\n3. Lightning bolt or star from yellow fondant\n4. POW! and BAM! lettering from fondant\n5. Distribute colorful sprinkles', 12, 75, '[{"item": "Kuchen-Mischung", "amount": "1 Packung"}, {"item": "Rote Glasur", "amount": "150g"}, {"item": "Blaue Glasur", "amount": "150g"}, {"item": "Gelber Fondant", "amount": "100g"}, {"item": "Bunte Streusel", "amount": "50g"}]', '[{"item": "Cake mix", "amount": "1 box"}, {"item": "Red glaze", "amount": "150g"}, {"item": "Blue glaze", "amount": "150g"}, {"item": "Yellow fondant", "amount": "100g"}, {"item": "Colorful sprinkles", "amount": "50g"}]', true),

('circus', 'Zirkuszelt-Kuchen', 'Circus Tent Cake', 'Ein bunter Kuchen der aussieht wie ein Zirkuszelt!', 'A colorful cake that looks like a circus tent!', '1. Runden Kuchen backen\n2. Rote und weiße Streifen aus Fondant\n3. Kleine Flagge oben drauf\n4. Popcorn und ErdNüsse als Deko drumherum\n5. Tierfiguren aufstellen', '1. Bake round cake\n2. Red and white stripes from fondant\n3. Small flag on top\n4. Popcorn and peanuts as decoration around\n5. Place animal figures', 12, 75, '[{"item": "Kuchen-Mischung", "amount": "1 Packung"}, {"item": "Roter Fondant", "amount": "150g"}, {"item": "weißer Fondant", "amount": "150g"}, {"item": "Popcorn", "amount": "100g"}, {"item": "Kleine Flagge", "amount": "1"}]', '[{"item": "Cake mix", "amount": "1 box"}, {"item": "Red fondant", "amount": "150g"}, {"item": "White fondant", "amount": "150g"}, {"item": "Popcorn", "amount": "100g"}, {"item": "Small flag", "amount": "1"}]', false),

('knight', 'Burg-Kuchen', 'Castle Cake', 'Eine essbare Ritterburg!', 'An edible knight castle!', '1. Rechteckigen Kuchen backen\n2. Graue Glasur auftragen\n3. Eiswaffeln als Tuerme\n4. Zinnen aus Butterkeksen schneiden\n5. Zugbruecke aus Schokolade\n6. Ritter-Figuren platzieren', '1. Bake rectangular cake\n2. Apply gray glaze\n3. Ice cream cones as towers\n4. Cut battlements from butter cookies\n5. Drawbridge from chocolate\n6. Place knight figures', 12, 90, '[{"item": "Kuchen-Mischung", "amount": "1 Packung"}, {"item": "Graue Glasur", "amount": "250g"}, {"item": "Eiswaffeln", "amount": "4"}, {"item": "Butterkekse", "amount": "1 Packung"}, {"item": "Schokolade", "amount": "100g"}]', '[{"item": "Cake mix", "amount": "1 box"}, {"item": "Gray glaze", "amount": "250g"}, {"item": "Ice cream cones", "amount": "4"}, {"item": "Butter cookies", "amount": "1 package"}, {"item": "Chocolate", "amount": "100g"}]', true),

('mermaid', 'Meerjungfrauen-Kuchen', 'Mermaid Cake', 'Ein zauberhafter Kuchen in Meeresfarben!', 'An enchanting cake in ocean colors!', '1. Runden Kuchen backen\n2. Tuerkis und blaue Buttercreme marmorieren\n3. Schwanz aus Fondant formen\n4. Muscheln und Seesterne aus Fondant\n5. Essbare Perlen verteilen\n6. Goldenen Glitzerstaub', '1. Bake round cake\n2. Marble turquoise and blue buttercream\n3. Shape tail from fondant\n4. Shells and starfish from fondant\n5. Distribute edible pearls\n6. Golden glitter dust', 12, 90, '[{"item": "Kuchen-Mischung", "amount": "1 Packung"}, {"item": "Buttercreme (tuerkis/blau)", "amount": "400g"}, {"item": "Fondant (tuerkis)", "amount": "150g"}, {"item": "Essbare Perlen", "amount": "50g"}, {"item": "Goldener Glitzerstaub", "amount": "10g"}]', '[{"item": "Cake mix", "amount": "1 box"}, {"item": "Buttercream (turquoise/blue)", "amount": "400g"}, {"item": "Fondant (turquoise)", "amount": "150g"}, {"item": "Edible pearls", "amount": "50g"}, {"item": "Golden glitter dust", "amount": "10g"}]', true),

('jungle', 'Dschungel-Kuchen', 'Jungle Cake', 'Ein wilder Kuchen mit Dschungel-Deko!', 'A wild cake with jungle decoration!', '1. Schokoladenkuchen backen\n2. Gruene Buttercreme als Dschungelboden\n3. Baeume aus Brezeln und gruener Glasur\n4. Tierfiguren im Dschungel platzieren\n5. Essbare Blumen als Pflanzen', '1. Bake chocolate cake\n2. Green buttercream as jungle floor\n3. Trees from pretzels and green glaze\n4. Place animal figures in jungle\n5. Edible flowers as plants', 12, 60, '[{"item": "Schokoladenkuchen-Mischung", "amount": "1 Packung"}, {"item": "Gruene Buttercreme", "amount": "300g"}, {"item": "Brezeln", "amount": "10"}, {"item": "Gruene Glasur", "amount": "100g"}, {"item": "Tierfiguren", "amount": "5"}]', '[{"item": "Chocolate cake mix", "amount": "1 box"}, {"item": "Green buttercream", "amount": "300g"}, {"item": "Pretzels", "amount": "10"}, {"item": "Green glaze", "amount": "100g"}, {"item": "Animal figures", "amount": "5"}]', true),

('no-theme', 'Konfetti-Kuchen', 'Confetti Cake', 'Ein froehlicher, bunter Geburtstagskuchen!', 'A cheerful, colorful birthday cake!', '1. Vanillekuchen backen\n2. Bunte Streusel in den Teig mischen (Konfetti-Effekt)\n3. weiße Buttercreme\n4. Bunte Streusel oben drauf\n5. Geburtstagskerzen\n6. Optional: Zuckerguss-Schriftzug', '1. Bake vanilla cake\n2. Mix colorful sprinkles into batter (confetti effect)\n3. White buttercream\n4. Colorful sprinkles on top\n5. Birthday candles\n6. Optional: icing lettering', 12, 45, '[{"item": "Vanillekuchen-Mischung", "amount": "1 Packung"}, {"item": "Bunte Streusel", "amount": "100g"}, {"item": "weiße Buttercreme", "amount": "300g"}, {"item": "Geburtstagskerzen", "amount": "1 Set"}]', '[{"item": "Vanilla cake mix", "amount": "1 box"}, {"item": "Colorful sprinkles", "amount": "100g"}, {"item": "White buttercream", "amount": "300g"}, {"item": "Birthday candles", "amount": "1 set"}]', true);


