INSERT INTO public.food_items (name_de, name_en, category, quantity_per_child, unit_de, unit_en) VALUES
('Wuerstchen', 'Sausages', 'savory', 2, 'Stück', 'pieces'),
('Mini-Pizza', 'Mini Pizza', 'savory', 2, 'Stück', 'pieces'),
('Mini-Burger', 'Mini Burgers', 'savory', 1.5, 'Stück', 'pieces'),
('Butterbrote', 'Sandwiches', 'savory', 2, 'Stück', 'pieces'),
('Chicken Nuggets', 'Chicken Nuggets', 'savory', 4, 'Stück', 'pieces'),
('Gemuesesticks', 'Veggie Sticks', 'snack', 1, 'Portion', 'portion'),
('Obstspieße', 'Fruit Skewers', 'snack', 1, 'Stück', 'pieces'),
('Popcorn', 'Popcorn', 'snack', 1, 'Tuete', 'bag'),
('Brezeln', 'Pretzels', 'snack', 2, 'Stück', 'pieces'),
('Chips', 'Chips', 'snack', 1, 'Portion', 'portion'),
('Gummibärchen', 'Gummy Bears', 'snack', 1, 'Tuete', 'bag'),
('Apfelsaft', 'Apple Juice', 'drink', 0.5, 'Liter', 'liters'),
('Wasser', 'Water', 'drink', 0.5, 'Liter', 'liters'),
('Kinderbowle', 'Kids Punch', 'drink', 0.3, 'Liter', 'liters'),
