-- ============================================================
-- INVITATION TEMPLATES (14 themes)
-- ============================================================
INSERT INTO public.invitation_templates (theme_slug, name_de, name_en, template_text_de, template_text_en, bg_color, accent_color, emoji) VALUES
('pirates', 'Piraten-Einladung', 'Pirate Invitation', 'Ahoi, {{childName}}!\n\nKomm an Bord! {{birthdayChild}} wird {{age}} Jahre alt und laedt dich zur Großen Piratenparty ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nOrt: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nArrr, wir freuen uns auf dich! 🏴‍☠️', 'Ahoy, {{childName}}!\n\nCome aboard! {{birthdayChild}} is turning {{age}} and invites you to the big pirate party!\n\nDate: {{date}}\nTime: {{time}}\nLocation: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nArrr, we look forward to seeing you! 🏴‍☠️', '#1E3A5F', '#FBBF24', '🏴‍☠️'),
('princess', 'Prinzessinnen-Einladung', 'Princess Invitation', 'Liebe/r {{childName}}!\n\nIhre Königliche Hoheit {{birthdayChild}} wird {{age}} Jahre alt und laedt dich zum Königlichen Ball ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nSchloss: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nWir freuen uns auf dich! 👑', 'Dear {{childName}}!\n\nHer Royal Highness {{birthdayChild}} is turning {{age}} and invites you to the royal ball!\n\nDate: {{date}}\nTime: {{time}}\nCastle: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nWe look forward to seeing you! 👑', '#FDF2F8', '#EC4899', '👑'),
('dinosaurs', 'Dino-Einladung', 'Dino Invitation', 'ROAAAR, {{childName}}!\n\n{{birthdayChild}} wird {{age}} Jahre alt und laedt dich zur Dino-Party ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nOrt: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nDino-stark, dass du kommst! 🦕', 'ROAAAR, {{childName}}!\n\n{{birthdayChild}} is turning {{age}} and invites you to the dino party!\n\nDate: {{date}}\nTime: {{time}}\nLocation: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nDino-mite that you are coming! 🦕', '#F0FDF4', '#16A34A', '🦕'),
('space', 'Weltraum-Einladung', 'Space Invitation', 'Achtung, {{childName}}!\n\n3... 2... 1... Start! {{birthdayChild}} wird {{age}} und laedt dich zur Weltraum-Mission ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nRaumstation: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nHouston, wir freuen uns auf dich! 🚀', 'Attention, {{childName}}!\n\n3... 2... 1... Launch! {{birthdayChild}} is turning {{age}} and invites you to the space mission!\n\nDate: {{date}}\nTime: {{time}}\nSpace Station: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nHouston, we look forward to seeing you! 🚀', '#1E1B4B', '#A78BFA', '🚀'),
('soccer', 'Fußball-Einladung', 'Soccer Invitation', 'Hallo {{childName}}!\n\nAnpfiff! {{birthdayChild}} wird {{age}} und laedt dich zum Großen Fußball-Turnier ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nStadion: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nToooor! Wir freuen uns auf dich! ⚽', 'Hello {{childName}}!\n\nKick-off! {{birthdayChild}} is turning {{age}} and invites you to the big soccer tournament!\n\nDate: {{date}}\nTime: {{time}}\nStadium: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nGoal! We look forward to seeing you! ⚽', '#F0FDF4', '#22C55E', '⚽'),
('detective', 'Detektiv-Einladung', 'Detective Invitation', 'Streng geheim, {{childName}}!\n\nFall Nr. {{age}}: {{birthdayChild}} braucht deine Hilfe bei der Geburtstagsparty!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nHauptquartier: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nDer Fall wartet auf dich! 🔍', 'Top Secret, {{childName}}!\n\nCase No. {{age}}: {{birthdayChild}} needs your help at the birthday party!\n\nDate: {{date}}\nTime: {{time}}\nHeadquarters: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nThe case is waiting for you! 🔍', '#F9FAFB', '#6B7280', '🔍'),
('unicorn', 'Einhorn-Einladung', 'Unicorn Invitation', 'Magische Gruesse, {{childName}}!\n\n{{birthdayChild}} wird {{age}} Jahre alt und laedt dich in die Einhorn-Welt ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nOrt: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nEs wird magisch! 🦄', 'Magical greetings, {{childName}}!\n\n{{birthdayChild}} is turning {{age}} and invites you to the unicorn world!\n\nDate: {{date}}\nTime: {{time}}\nLocation: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nIt is going to be magical! 🦄', '#FDF4FF', '#EC4899', '🦄'),
('animals', 'Tier-Einladung', 'Animal Invitation', 'Hallo {{childName}}!\n\n{{birthdayChild}} wird {{age}} und feiert eine tierisch gute Party!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nOrt: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nTierisch toll, dass du kommst! 🐾', 'Hello {{childName}}!\n\n{{birthdayChild}} is turning {{age}} and is having an amazing animal party!\n\nDate: {{date}}\nTime: {{time}}\nLocation: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nWe look forward to seeing you! 🐾', '#FFFDF7', '#A16207', '🐾'),
('superhero', 'Superhelden-Einladung', 'Superhero Invitation', 'Alarm, {{childName}}!\n\n{{birthdayChild}} wird {{age}} und braucht DEINE Superkraefte bei der Heldenparty!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nHauptquartier: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nDie Stadt braucht dich! 🦸', 'Alert, {{childName}}!\n\n{{birthdayChild}} is turning {{age}} and needs YOUR superpowers at the hero party!\n\nDate: {{date}}\nTime: {{time}}\nHeadquarters: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nThe city needs you! 🦸', '#FEF2F2', '#DC2626', '🦸'),
('circus', 'Zirkus-Einladung', 'Circus Invitation', 'Hereinspaziert, {{childName}}!\n\nManege frei! {{birthdayChild}} wird {{age}} und laedt dich zur Großen Zirkus-Show ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nZirkuszelt: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nVorhang auf! 🎪', 'Step right in, {{childName}}!\n\nLadies and gentlemen! {{birthdayChild}} is turning {{age}} and invites you to the big circus show!\n\nDate: {{date}}\nTime: {{time}}\nCircus Tent: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nCurtain up! 🎪', '#FFFBEB', '#F59E0B', '🎪'),
('knight', 'Ritter-Einladung', 'Knight Invitation', 'Edle/r {{childName}}!\n\nRitter {{birthdayChild}} wird {{age}} und laedt dich zum Großen Ritterturnier ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nBurg: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nfür Ehre und Kuchen! ⚔️', 'Noble {{childName}}!\n\nSir/Lady {{birthdayChild}} is turning {{age}} and invites you to the grand knight tournament!\n\nDate: {{date}}\nTime: {{time}}\nCastle: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nFor honor and cake! ⚔️', '#F5F5F4', '#78716C', '⚔️'),
('mermaid', 'Meerjungfrauen-Einladung', 'Mermaid Invitation', 'Hallo {{childName}}!\n\nTauch ein! {{birthdayChild}} wird {{age}} und laedt dich in die Unterwasserwelt ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nOrt: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nWir freuen uns riesig auf dich! 🧜‍♀️', 'Hello {{childName}}!\n\nDive in! {{birthdayChild}} is turning {{age}} and invites you to the underwater world!\n\nDate: {{date}}\nTime: {{time}}\nLocation: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nWe are so excited to see you! 🧜‍♀️', '#ECFEFF', '#06B6D4', '🧜‍♀️'),
('jungle', 'Dschungel-Einladung', 'Jungle Invitation', 'Abenteurer/in {{childName}}!\n\n{{birthdayChild}} wird {{age}} und laedt dich zur Großen Dschungel-Expedition ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nBasislager: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nDas Abenteuer ruft! 🌴', 'Adventurer {{childName}}!\n\n{{birthdayChild}} is turning {{age}} and invites you to the big jungle expedition!\n\nDate: {{date}}\nTime: {{time}}\nBase Camp: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nAdventure awaits! 🌴', '#F0FDF4', '#15803D', '🌴'),
('no-theme', 'Party-Einladung', 'Party Invitation', 'Liebe/r {{childName}}!\n\n{{birthdayChild}} wird {{age}} Jahre alt und laedt dich zur Großen Geburtstagsparty ein!\n\nDatum: {{date}}\nUhrzeit: {{time}}\nOrt: {{address}}\n\nBitte antworte bis: {{rsvpDate}}\n{{bringNote}}\n\nWir freuen uns auf dich! 🎈🎂', 'Dear {{childName}}!\n\n{{birthdayChild}} is turning {{age}} and invites you to the big birthday party!\n\nDate: {{date}}\nTime: {{time}}\nLocation: {{address}}\n\nPlease RSVP by: {{rsvpDate}}\n{{bringNote}}\n\nWe look forward to seeing you! 🎈🎂', '#FFFDF7', '#7C3AED', '🎈');
